defmodule WebhookProxyWeb.ProxyController do
  use WebhookProxyWeb, :controller

  alias HTTPoison

  def fetch(conn, %{"url" => url}) do
    case HTTPoison.get(url) do
      {:ok, response} ->
        conn
        |> put_status(response.status_code)
        |> text(response.body)

      {:error, error} ->
        conn
        |> put_status(500)
        |> text("Error fetching content: #{inspect(error)}")
    end
  end

  def fetch(conn, _) do
    conn
